&lt;li id=&quot;3&quot; class=&quot;paragraph--da25a3913a1dd210&quot; style=&quot;font-size: 10pt;&quot; data-paragraph=&quot;true&quot; data-type=&quot;p&quot;&gt;&lt;span class=&quot;text--da25a3913a1dd210&quot; style=&quot;font-size: 10pt;&quot;&gt;인게임 아이템 및 재화 지급/관리&lt;/span&gt;&lt;/li&gt;
&lt;li id=&quot;4&quot; class=&quot;paragraph--da25a3913a1dd210&quot; style=&quot;font-size: 10pt;&quot; data-paragraph=&quot;true&quot; data-type=&quot;p&quot;&gt;&lt;span class=&quot;text--da25a3913a1dd210&quot; style=&quot;font-size: 10pt;&quot;&gt;글로벌 유저 커뮤니티 동향 파악 및 인사이트 도출&lt;/span&gt;&lt;/li&gt;
&lt;li id=&quot;5&quot; class=&quot;paragraph--da25a3913a1dd210&quot; style=&quot;font-size: 10pt;&quot; data-paragraph=&quot;true&quot; data-type=&quot;p&quot;&gt;&lt;span class=&quot;text--da25a3913a1dd210&quot; style=&quot;font-size: 10pt;&quot;&gt;불건전 이용자 데이터 확인 및 대응 진행&lt;/span&gt;&lt;/li&gt;
